DECLARE @baseDate date = CAST(GETDATE() AS date);
DECLARE @prev1 date = DATEADD(month, -1, @baseDate);
DECLARE @prev2 date = DATEADD(month, -2, @baseDate);
DECLARE @prev3 date = DATEADD(month, -3, @baseDate);

DECLARE @m1 int = MONTH(@prev1), @y1 int = YEAR(@prev1);
DECLARE @m2 int = MONTH(@prev2), @y2 int = YEAR(@prev2);
DECLARE @m3 int = MONTH(@prev3), @y3 int = YEAR(@prev3);

-- previous month, previous year
DECLARE @y1prev int = @y1 - 1;

SELECT
  SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @y1 THEN S.TFtal ELSE 0 END) AS sumPreviousMonthCurrentYear,
  SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @y1prev THEN S.TFtal ELSE 0 END) AS sumPreviousMonthPreviousYear,
  (
    SUM(CASE WHEN MONTH(S.ValueDate) = @m3 AND YEAR(S.ValueDate) = @y3 THEN S.TFtal ELSE 0 END) +
    SUM(CASE WHEN MONTH(S.ValueDate) = @m2 AND YEAR(S.ValueDate) = @y2 THEN S.TFtal ELSE 0 END) +
    SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @y1 THEN S.TFtal ELSE 0 END)
  ) / 3.0 AS averageLastThreeMonths
FROM dbo.Stock S
WHERE
  S.AccountKey = @userExtId
  AND S.DocumentID IN (6,11)
  AND S.TFtal IS NOT NULL
  AND (
    (YEAR(S.ValueDate) = @y1 AND MONTH(S.ValueDate) IN (@m1, @m2, @m3))
    OR (YEAR(S.ValueDate) = @y1prev AND MONTH(S.ValueDate) = @m1)
  );

DECLARE @baseDate date = CAST(GETDATE() AS date);
DECLARE @prev1 date = DATEADD(month, -1, @baseDate);
DECLARE @prev2 date = DATEADD(month, -2, @baseDate);
DECLARE @prev3 date = DATEADD(month, -3, @baseDate);

DECLARE @m1 int = MONTH(@prev1), @y1 int = YEAR(@prev1);
DECLARE @m2 int = MONTH(@prev2), @y2 int = YEAR(@prev2);
DECLARE @m3 int = MONTH(@prev3), @y3 int = YEAR(@prev3);
DECLARE @yPrev int = @y1 - 1;

SELECT
  SM.ItemKey,
  SM.ItemName,
  SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @y1 THEN SM.Quantity ELSE 0 END) AS sumPreviousMonthCurrentYear,
  SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @yPrev THEN SM.Quantity ELSE 0 END) AS sumPreviousMonthPreviousYear,
  (
    SUM(CASE WHEN MONTH(S.ValueDate) = @m3 AND YEAR(S.ValueDate) = @y3 THEN SM.Quantity ELSE 0 END) +
    SUM(CASE WHEN MONTH(S.ValueDate) = @m2 AND YEAR(S.ValueDate) = @y2 THEN SM.Quantity ELSE 0 END) +
    SUM(CASE WHEN MONTH(S.ValueDate) = @m1 AND YEAR(S.ValueDate) = @y1 THEN SM.Quantity ELSE 0 END)
  ) / 3.0 AS averageLastThreeMonths
FROM dbo.Stock S
JOIN dbo.StockMoves SM
  ON S.ID = SM.StockID
WHERE
  S.AccountKey = @userExtId
  AND S.DocumentID IN (6,11)
  AND S.Status = 1
  AND (
    (YEAR(S.ValueDate) = @y1 AND MONTH(S.ValueDate) IN (@m1, @m2, @m3))
    OR (YEAR(S.ValueDate) = @yPrev AND MONTH(S.ValueDate) = @m1)
  )
GROUP BY SM.ItemKey, SM.ItemName;

SELECT [Note]
FROM dbo.ExtraNotes
WHERE NoteID = @NoteId AND KeF = @Kef;
